// Add any manually tracked applications here
// These will be merged with Gmail results every run
const manualEntries = [
  {
    Date:        '2026-02-09',
    Sender:      'Telstra',
    SenderEmail: 'noreply@team.telstra.com',
    Subject:     'Interview',
    Message:     'Interview confirmation',
    Category:    'Interview'
  },
  // Add more manual entries here as needed:
  // {
  //   Date:        'YYYY-MM-DD',
  //   Sender:      'Company Name',
  //   SenderEmail: 'email@company.com',
  //   Subject:     'Subject line',
  //   Message:     'Brief description',
  //   Category:    'Applied / Interview / Unsuccessful'
  // },
];

return manualEntries.map(e => ({ json: e }));

const senderItems = $input.all();

const knownSenders = senderItems
  .map(item => item.json.Sender || item.json.sender || '')
  .filter(s => s && s.length > 2)
  .map(s => {
    const cleaned = s.trim().toLowerCase();
    return cleaned.includes('@') ? cleaned.split('@')[1] : cleaned;
  })
  .filter(Boolean);

const uniqueDomains = [...new Set(knownSenders)];

const subjectTerms = [
  '"thank you for your application"',
  '"thank you for applying"',
  '"thanks for applying"',
  '"thanks for your interest"',
  '"thank you for your interest"',
  '"application received"',
  '"application submitted"',
  '"successfully submitted"',
  '"receipt confirmation"',
  '"we have received your"',
  '"we\'ve received your"',
  '"viewed your application"',
  '"your application for"',
  '"job application"',
  '"job opportunity"',
  '"application confirmation"',
  '"application acknowledgment"',
  '"application acknowledgement"',
  '"your application has been"',
  '"application for the position"',
  '"application for the role"',
  '"unsuccessful job application"',
  '"not been successful"',
  '"regret to inform"',
  '"no longer recruiting"',
];

const subjectPart = subjectTerms.map(t => `subject:(${t})`).join(' OR ');
const fromPart = uniqueDomains.length > 0
  ? uniqueDomains.map(d => `from:(${d})`).join(' OR ')
  : '';

const fullQuery = fromPart
  ? `(${subjectPart} OR ${fromPart}) after:2025/12/01`
  : `(${subjectPart}) after:2025/12/01`;

console.log(`Query built with ${uniqueDomains.length} known domains`);
return [{ json: { gmailQuery: fullQuery, knownDomains: uniqueDomains } }];

const response = $input.first().json;
const messages = response.messages || [];
console.log(`Found ${messages.length} individual messages (not thread-grouped)`);
if (messages.length === 0) {
  return [{ json: { messageId: null, _noMessages: true } }];
}
return messages.map(msg => ({ json: { messageId: msg.id } }));

const items = $input.all();
const results = [];

function decodeBase64Url(str) {
  if (!str) return '';
  try {
    const b64 = str.replace(/-/g, '+').replace(/_/g, '/');
    return Buffer.from(b64, 'base64').toString('utf-8');
  } catch (_) { return ''; }
}

function extractBody(payload) {
  let html = '', text = '';
  if (!payload) return { html, text };
  const mime = payload.mimeType || '';
  if (mime === 'text/html' && payload.body && payload.body.data) html = decodeBase64Url(payload.body.data);
  else if (mime === 'text/plain' && payload.body && payload.body.data) text = decodeBase64Url(payload.body.data);
  if (payload.parts) {
    for (const part of payload.parts) {
      const sub = extractBody(part);
      if (sub.html) html = sub.html;
      if (sub.text && !text) text = sub.text;
    }
  }
  return { html, text };
}

for (const item of items) {
  const msg = item.json;
  if (!msg || !msg.payload) continue;

  const headers = {};
  (msg.payload.headers || []).forEach(h => { headers[h.name.toLowerCase()] = h.value; });

  let dateReceived = 'Unknown';
  try {
    const raw = headers['date'] || msg.internalDate;
    if (raw) {
      const parsed = typeof raw === 'string' ? new Date(raw) : new Date(parseInt(raw));
      if (!isNaN(parsed)) {
        dateReceived = parsed.toLocaleDateString('en-CA', {
          timeZone: 'Australia/Melbourne',
          year: 'numeric', month: '2-digit', day: '2-digit'
        });
      }
    }
  } catch (_) {}

  const rawFrom = (headers['from'] || '').replace(/^from:\s*/i, '').trim();
  let sender = 'Unknown', senderEmail = '';
  if (rawFrom) {
    const emailMatch = rawFrom.match(/<([^>]+)>/);
    senderEmail = emailMatch ? emailMatch[1].toLowerCase() : rawFrom.toLowerCase();
    const nameMatch = rawFrom.match(/^"?([^"<]+?)"?\s*<[^>]+>$/);
    sender = nameMatch ? nameMatch[1].trim() : senderEmail;
  }

  const subject = headers['subject'] || '(No Subject)';
  const { html: rawHtml, text: rawText } = extractBody(msg.payload);

  let message = '';
  if (rawHtml) {
    message = rawHtml
      .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]*>/g, ' ')
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/&nbsp;/g, ' ').replace(/&quot;/g, '"').replace(/&apos;/g, "'")
      .replace(/&#96;/g, '`').replace(/&#8226;/g, ' ').replace(/&#169;/g, '')
      .replace(/&#[0-9]+;/g, ' ').replace(/&[a-z]+;/g, ' ')
      .replace(/\s+/g, ' ').trim();
  } else if (rawText) {
    message = rawText.replace(/\s+/g, ' ').trim();
  } else if (msg.snippet) {
    message = msg.snippet;
  }

  const msgForLLM = message.length > 1500 ? message.slice(0, 1500) + '...' : message;
  const messagesJson = JSON.stringify([
    { role: 'system', content: `Classify this job application email. Output ONE word only on the final line: Applied, Interview, or Unsuccessful.

Priority order (check in this order, stop at first match):

1. UNSUCCESSFUL — email contains: not selected, not successful, will not be progressing, regret to inform, regret to advise, no longer recruiting, position closed, role filled, moving forward with other candidates

2. INTERVIEW — email contains: interview, phone screen, video interview, schedule a time, book a time, assessment, next stage, shortlisted

3. APPLIED — email contains: application received, application submitted, successfully submitted, viewed your application, reviewing applications, under review, thank you for applying, we will be in touch, we are reviewing

Your response MUST end with exactly one of these three words on its own line:
Applied
Interview
Unsuccessful` },
    { role: 'user', content: `Subject: ${subject}\n\nMessage:\n${msgForLLM}` }
  ]);

  results.push({ json: { messageId: msg.id, dateReceived, sender, senderEmail, subject, message, msgForLLM, messagesJson } });
}
return results;

const llmItems = $input.all();
const emailItems = $('Extract & Clean Email Fields13').all();

return llmItems.map((item, i) => {
  const email = emailItems[i] ? emailItems[i].json : {};
  let category = 'Unknown';
  try {
    const choice = item.json?.choices?.[0];
    const content   = (choice?.message?.content   || '').trim();
    const reasoning = (choice?.message?.reasoning || '').trim();
    const raw = content !== '' ? content : reasoning;
    const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length > 0);
    const lastWord = (lines[lines.length - 1] || '').replace(/[^a-zA-Z]/g, '').toLowerCase();
    if      (lastWord === 'applied')      category = 'Applied';
    else if (lastWord === 'interview')    category = 'Interview';
    else if (lastWord === 'unsuccessful') category = 'Unsuccessful';
    else {
      const fullText = raw.toLowerCase();
      if      (/\binterview\b/.test(fullText)) category = 'Interview';
      else if (/unsuccessful|not.{0,20}selected|not.{0,20}progressing|no longer.{0,20}recruit|regret|unfortunately/.test(fullText)) category = 'Unsuccessful';
      else if (/applied|received|under review|reviewing|acknowledge|submitted|viewed your application/.test(fullText)) category = 'Applied';
    }
  } catch (_) {}
  return {
    json: {
      MessageId:   email.messageId   || '',
      Date:        email.dateReceived || '',
      Sender:      email.sender       || '',
      SenderEmail: email.senderEmail  || '',
      Subject:     email.subject      || '',
      Message:     (email.message || '').replace(/\r?\n/g, ' ').replace(/"/g, "'").slice(0, 500),
      Category:    category
    }
  };
});

const emailItems = $('Merge Gmail + Manual').all();
const knownItems = $('Read Known Senders6').all();
const knownSet = new Set(
  knownItems
    .map(item => (item.json.Sender || item.json.sender || '').toLowerCase().trim())
    .filter(s => s.length > 0)
);

const newDomains = [];
const skip = ['gmail.com','yahoo.com','hotmail.com','outlook.com','icloud.com','live.com'];

for (const item of emailItems) {
  const senderEmail = (item.json.SenderEmail || '').toLowerCase().trim();
  if (!senderEmail.includes('@')) continue;
  const domain = senderEmail.split('@')[1];
  if (!domain || skip.includes(domain) || knownSet.has(domain)) continue;
  if (!newDomains.includes(domain)) {
    newDomains.push(domain);
    knownSet.add(domain);
  }
}

if (newDomains.length === 0) return [{ json: { _noNewSenders: true, count: 0 } }];
return newDomains.map(domain => ({ json: { Sender: domain } }));

const allIds = $input.all();
const processed = new Set(
  $('Read Results Sheet').all()
    .map(i => i.json.MessageId)
    .filter(Boolean)
);

const filtered = allIds.filter(item => !processed.has(item.json.messageId));
console.log(`Skipping ${allIds.length - filtered.length} already-processed, ${filtered.length} new to classify`);
return filtered.length > 0 ? filtered : [{ json: { messageId: null, _noMessages: true } }];
